const now = new Date();
const colombiaOffset = -5;
const currentHour = (now.getUTCHours() + 24 + colombiaOffset) % 24;
const currentMinute = now.getUTCMinutes();
const currentTime = currentHour * 60 + currentMinute;

const [wakeHour, wakeMin] = ($json.wake_up_time || '07:00').split(':').map(Number);
const wakeTime = wakeHour * 60 + wakeMin;

const minutesSinceWake = currentTime - wakeTime;
let mealType;
if (minutesSinceWake <= 90) {
  mealType = 'breakfast';
} else if (minutesSinceWake <= 330) {
  mealType = 'lunch';
} else {
  mealType = 'dinner';
}

const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
const colombiaDate = new Date(now.getTime() + colombiaOffset * 3600 * 1000);
const today = dayNames[colombiaDate.getUTCDay()];

const plan = typeof $json.plan_json === 'string' ? JSON.parse($json.plan_json) : $json.plan_json;
const todayPlan = plan.days?.[today];
const meal = todayPlan?.meals?.find(m => m.type === mealType);

if (!meal) {
  return [{ json: { skip: true } }];
}

const foodList = meal.foods ? meal.foods.map(f => '- ' + f.name + ': ' + f.quantity + ' ' + (f.unit || '')).join('\n') : '';
const mealTypeSpanish = { breakfast: 'desayuno', lunch: 'comida', dinner: 'cena', snack: 'snack' };

return [{
  json: {
    skip: false,
    telegramId: $json.telegram_id,
    firstName: $json.first_name,
    mealType: mealTypeSpanish[mealType] || mealType,
    mealName: meal.name,
    totalCalories: meal.total_calories,
    foodList
  }
}];

